// ─── UTILS ───────────────────────────────────────────────────
function genOrden() {
  const d = new Date()
  const dd = String(d.getDate()).padStart(2,'0')
  const mm = String(d.getMonth()+1).padStart(2,'0')
  const yy = String(d.getFullYear()).slice(2)
  const seq = String(OTs.length+1).padStart(2,'0')
  return dd+'/'+mm+'/'+yy+'-'+seq
}
function badgeHtml(estado) {
  const map = {'En revisión':'open','En reparación':'repair','Esperando repuesto':'waiting','Listo para entrega':'done','Entregado':'done','Garantía':'warranty','Presupuesto':'budget'}
  return '<span class="badge '+(map[estado]||'open')+'">'+estado+'</span>'
}
function val(id) { return (document.getElementById(id)||{}).value||'' }
function setVal(id,v) { const el=document.getElementById(id); if(el&&v!==undefined) el.value=v }
function showAlert(id,msg,type,ms) {
  type=type||'success'; ms=ms||3500
  const el=document.getElementById(id); if(!el) return
  el.textContent=msg; el.className='alert '+type; el.classList.remove('hidden')
  setTimeout(()=>el.classList.add('hidden'),ms)
}
function isAdmin() { return currentUser&&currentUser.rol==='admin' }
function isOperador() { return currentUser&&currentUser.rol==='operador' }
function getTecnicos() { return Usuarios.filter(u=>u.rol==='tecnico') }

// ─── NOTIFICACIONES ──────────────────────────────────────────
async function crearNotificacion(paraUsuarioId, tipo, mensaje, otId) {
  const n = { id: genUUID(), para_usuario_id: paraUsuarioId, tipo, mensaje, ot_id: otId||null, leida: false }
  Notificaciones.unshift({...n, paraUsuarioId, otId})
  await SB.insert('notificaciones', n)
}

function getMisNotificaciones() {
  if(!currentUser) return []
  return Notificaciones.filter(function(n){
    const pid = n.para_usuario_id || n.paraUsuarioId
    return pid===currentUser.id && !n.leida
  })
}

async function marcarLeida(id) {
  const n = Notificaciones.find(x=>x.id===id)
  if(n) { n.leida=true; await SB.update('notificaciones', id, {leida:true}) }
  renderNotifBadge()
}

async function marcarTodasLeidas() {
  const pending = getMisNotificaciones()
  pending.forEach(function(n){n.leida=true})
  await Promise.all(pending.map(function(n){ return SB.update('notificaciones', n.id, {leida:true}) }))
  renderNotifBadge()
  document.getElementById('notif-panel')?.classList.add('hidden')
}

function renderNotifBadge() {
  const count = getMisNotificaciones().length
  const badge = document.getElementById('notif-badge')
  if(badge) { badge.textContent=count; badge.style.display=count>0?'flex':'none' }
  const btn = document.getElementById('notif-btn')
  if(btn) btn.style.color = count>0 ? '#dc2626' : '#888'
}

function toggleNotifPanel() {
  const panel = document.getElementById('notif-panel')
  if(!panel) return
  const isHidden = panel.classList.contains('hidden')
  panel.classList.toggle('hidden')
  if(isHidden) {
    renderNotifPanel()
    // Close when clicking outside
    setTimeout(function() {
      document.addEventListener('click', function closePanel(e) {
        if(!panel.contains(e.target) && e.target.id !== 'notif-btn' && !e.target.closest('#notif-btn')) {
          panel.classList.add('hidden')
          document.removeEventListener('click', closePanel)
        }
      })
    }, 100)
  }
}

function renderNotifPanel() {
  const panel = document.getElementById('notif-panel')
  if(!panel) return
  const notifs = getMisNotificaciones()
  if(!notifs.length) {
    panel.innerHTML = '<div style="padding:16px;text-align:center;color:#aaa;font-size:13px"><i class="ti ti-bell-off" style="font-size:24px;display:block;margin-bottom:8px"></i>Sin notificaciones</div>'
    return
  }
  panel.innerHTML = '<div style="padding:10px 12px;border-bottom:1px solid #f0f0f0;display:flex;justify-content:space-between;align-items:center"><span style="font-size:12px;font-weight:600">'+notifs.length+' notificacion'+( notifs.length!==1?'es':'')+' nuevas</span><button onclick="marcarTodasLeidas()" style="font-size:11px;color:#185FA5;background:none;border:none;cursor:pointer">Marcar todas leídas</button></div>' +
  notifs.map(n=>'<div style="padding:12px;border-bottom:1px solid #f5f5f4;cursor:pointer" onclick="abrirNotif(\''+n.id+'\',\''+( n.otId||'')+'\')">'+
    '<div style="display:flex;align-items:flex-start;gap:10px">'+
    '<div style="width:32px;height:32px;border-radius:50%;background:#DBEAFE;display:flex;align-items:center;justify-content:center;flex-shrink:0"><i class="ti ti-tool" style="color:#185FA5;font-size:14px"></i></div>'+
    '<div><div style="font-size:13px;font-weight:500;color:#1a1a1a">'+n.mensaje+'</div>'+
    '<div style="font-size:11px;color:#aaa;margin-top:2px">'+new Date(n.fecha).toLocaleString('es-CL')+'</div></div></div></div>'
  ).join('')
}

function abrirNotif(notifId, otId) {
  marcarLeida(notifId)
  document.getElementById('notif-panel')?.classList.add('hidden')
  document.getElementById('notif-popup')?.remove()
  if(otId) {
    const o = OTs.find(function(x){return x.id===otId})
    if(o) {
      if(isAdmin()||isOperador()) openOT(otId)
      else openInforme(otId)
    }
  }
}

async function checkNotifLoop() {
  if(!currentUser) return
  try {
    // Refresh OTs
    const freshOTs = await SB.select('ots')
    if(freshOTs) {
      OTs = freshOTs
      // Re-render lista if currently on lista or dashboard view
      if(currentViewName === 'lista') renderOTList()
      if(currentViewName === 'dashboard') renderDashboard()
    }

    // Refresh solicitudes
    const freshSol = await SB.select('solicitudes')
    if(freshSol) {
      Solicitudes = freshSol
      updateBadgeSol()
      if(currentViewName === 'solicitudes') renderSolicitudes()
    }

    // Refresh notificaciones
    const fresh = await SB.select('notificaciones', 'para_usuario_id=eq.'+currentUser.id+'&leida=eq.false&order=fecha.desc')
    if(fresh) {
      const oldIds = new Set(Notificaciones.filter(function(n){return !n.leida}).map(function(n){return n.id}))
      Notificaciones = Notificaciones.filter(function(n){return n.leida})
      fresh.forEach(function(n){
        n.paraUsuarioId = n.para_usuario_id
        n.otId = n.ot_id
        if(!oldIds.has(n.id)) n._shown = false
        Notificaciones.unshift(n)
      })
      const newest = getMisNotificaciones().find(function(n){return !n._shown})
      if(newest) { newest._shown=true; showPopupNotif(newest) }
    }
  } catch(e) {}
  renderNotifBadge()
}

function showPopupNotif(n) {
  const existing = document.getElementById('notif-popup')
  if(existing) existing.remove()
  const el = document.createElement('div')
  el.id = 'notif-popup'
  el.style.cssText = 'position:fixed;bottom:24px;right:24px;background:#fff;border:1px solid #ddd;border-radius:14px;padding:16px 20px;box-shadow:0 8px 32px rgba(0,0,0,0.15);z-index:9999;max-width:320px;animation:slideIn 0.3s ease'
  el.innerHTML = '<div style="display:flex;align-items:flex-start;gap:12px">'+
    '<div style="width:36px;height:36px;border-radius:50%;background:#DBEAFE;display:flex;align-items:center;justify-content:center;flex-shrink:0"><i class="ti ti-bell" style="color:#185FA5;font-size:18px"></i></div>'+
    '<div style="flex:1"><div style="font-size:13px;font-weight:600;color:#1a1a1a;margin-bottom:4px">Nueva asignación</div>'+
    '<div style="font-size:12px;color:#555">'+n.mensaje+'</div>'+
    '<button onclick="abrirNotif(\''+n.id+'\',\''+(n.otId||'')+'\')" style="margin-top:8px;padding:5px 12px;background:#185FA5;color:#fff;border:none;border-radius:6px;font-size:12px;cursor:pointer">Ver orden</button></div>'+
    '<button onclick="this.closest(\'#notif-popup\').remove()" style="background:none;border:none;cursor:pointer;color:#aaa;font-size:18px;line-height:1;flex-shrink:0">×</button></div>'
  document.body.appendChild(el)
  setTimeout(()=>el.remove(), 8000)
}

